# Worked focus: http-py-request-field-injection — Reject control characters and unsafe dynamic structure in targets and fields and rely on maintained encoders. Demonstrate the result through Python 3.14 urllib, http.client, ssl, typed protocols, and fixture transports.
def worked_http_py_security_boundaries_2(scheme: str, host_allowed: bool, private_address: bool, redirect_allowed: bool) -> dict[str, object]:
    assert isinstance(scheme, str)
    if scheme.casefold() != "https":
        return {"accepted": False, "reason": "scheme"}
    if not host_allowed or private_address:
        return {"accepted": False, "reason": "destination"}
    if not redirect_allowed:
        return {"accepted": False, "reason": "redirect"}
    return {"accepted": True, "reason": "bounded authority"}

